prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName ?incomingCount ?outgoingCount WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task bbo:name ?taskName .
  ?task tai:belongsTo ?choreo .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "4ac969819d6749d495c4f3be5f4745de" .

  {
    SELECT ?task (COUNT(DISTINCT ?inFlow) AS ?incomingCount) (COUNT(DISTINCT ?outFlow) AS ?outgoingCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo .
      OPTIONAL { ?inFlow a bbo:SequenceFlow . ?inFlow bbo:has_targetRef ?task . }
      OPTIONAL { ?outFlow a bbo:SequenceFlow . ?outFlow bbo:has_sourceRef ?task . }
    }
    GROUP BY ?task
  }

  FILTER(?incomingCount = 0 || ?outgoingCount = 0)
}
ORDER BY ?taskName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName ?incomingCount ?outgoingCount (IF(?incomingCount > 0 && ?outgoingCount > 0, "Executable", "Not Executable") AS ?status) WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task bbo:name ?taskName .
  ?task tai:belongsTo ?choreo .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "4ac969819d6749d495c4f3be5f4745de" .

  {
    SELECT ?task (COUNT(DISTINCT ?inFlow) AS ?incomingCount) (COUNT(DISTINCT ?outFlow) AS ?outgoingCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo .
      OPTIONAL { ?inFlow a bbo:SequenceFlow . ?inFlow bbo:has_targetRef ?task . }
      OPTIONAL { ?outFlow a bbo:SequenceFlow . ?outFlow bbo:has_sourceRef ?task . }
    }
    GROUP BY ?task
  }
}
ORDER BY ?taskName
